## Key Code Structure (Pseudocode)

```typescript
// api/client.ts

const DEFAULT_RETRY_CONFIG = {
  maxAttempts: 3,
  baseDelayMs: 100,
  maxDelayMs: 10000,
};

function getOrCreateRequestId(headers?: Record<string, string>): string {
  return headers?.['x-request-id'] || crypto.randomUUID();
}

async function withRetry<T>(
  fetchFn: () => Promise<Response>,
  requestId: string,
  config = DEFAULT_RETRY_CONFIG
): Promise<Response> {
  let lastError: Error | null = null;

  for (let attempt = 0; attempt < config.maxAttempts; attempt++) {
    try {
      const response = await fetchFn();

      // C1: Do NOT retry on 4xx
      if (response.status >= 400 && response.status < 500) {
        return response;
      }

      // Retry on 5xx
      if (response.status >= 500) {
        if (attempt < config.maxAttempts - 1) {
          const delay = Math.min(
            config.baseDelayMs * Math.pow(2, attempt),
            config.maxDelayMs
          );
          logger.info(`Retry attempt ${attempt + 1}`, {
            requestId,
            delay,
            status: response.status,
          });
          await sleep(delay);
          continue;
        }
      }

      return response;
    } catch (error) {
      lastError = error as Error;
      if (attempt < config.maxAttempts - 1) {
        const delay = Math.min(
          config.baseDelayMs * Math.pow(2, attempt),
          config.maxDelayMs
        );
        logger.info(`Retry attempt ${attempt + 1} after error`, {
          requestId,
          delay,
          error: lastError.message,
        });
        await sleep(delay);
      }
    }
  }

  throw lastError || new Error('Max retries exceeded');
}

// Wrap existing fetch calls:
export async function fetchData(url: string, options?: RequestInit) {
  const requestId = getOrCreateRequestId(options?.headers as any);
  return withRetry(
    () => fetch(url, options),
    requestId
  );
}
```

